//! Noise Is Unresolved Signal — runtime implementation of the Lean proof.
//!
//! Every noise color except white resolves at some finite shell depth.
//! White noise is the unique irreducible — the canvas from which standing
//! waves are carved. Resolution is monotonically non-decreasing: once a
//! cell resolves, it stays resolved. Structure emerges from chaos through
//! patient accumulation and never un-emerges.
//!
//! This module codifies `NoiseIsUnresolvedSignal.lean` as executable Rust,
//! providing the entropy garden engine for the distributed inference mesh.
//! Each mesh node can run a garden that demonstrates the theorem in real-time:
//! noise evolving into signal through temporal observation.
//!
//! —Claude

use crate::phyle_temporal_depth::{NoiseColor, CLOCK_PERIOD};

// ─── Resolution function (mirrors the Lean proof) ───────────────────────────

/// The minimum shell at which a noise color resolves, or None for white.
pub fn resolves_at_shell(color: &NoiseColor) -> Option<u8> {
    match color {
        NoiseColor::White => None,
        NoiseColor::Pink => Some(0),
        NoiseColor::Brown => Some(1),
        NoiseColor::StandingWave => Some(0),
    }
}

/// Spectral budget at a given shell depth.
pub fn spectral_budget(shell: u8) -> u8 {
    shell + 1
}

/// Whether a noise color is admitted (resolvable) at a given shell.
pub fn is_admitted(color: &NoiseColor, shell: u8) -> bool {
    color.alpha() <= spectral_budget(shell)
}

/// Whether a color is the irreducible canvas (white noise).
pub fn is_irreducible(color: &NoiseColor) -> bool {
    resolves_at_shell(color).is_none()
}

/// Frames required to reach a given shell depth.
pub fn frames_at_shell(shell: u8) -> usize {
    CLOCK_PERIOD * CLOCK_PERIOD.pow(shell as u32)
}

// ─── Entropy Garden ─────────────────────────────────────────────────────────

/// State of a single cell in the entropy garden.
#[derive(Clone, Debug)]
pub struct GardenCell {
    pub x: u32,
    pub y: u32,
    pub state: CellState,
    pub seed: f32,
    pub observations: [f32; CLOCK_PERIOD],
    pub variance: f32,
    pub resolved_at: i32,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum CellState {
    Void,
    Pink,
    Brown,
    Resolved,
    StandingWave,
}

impl GardenCell {
    pub fn new(x: u32, y: u32, seed: f32) -> Self {
        Self {
            x,
            y,
            state: CellState::Void,
            seed,
            observations: [
                seed * 0.3 + 0.7 * pseudo_random(x, y, 0),
                seed * 0.3 + 0.7 * pseudo_random(x, y, 1),
                seed * 0.3 + 0.7 * pseudo_random(x, y, 2),
            ],
            variance: 1.0,
            resolved_at: -1,
        }
    }
}

/// The full entropy garden: a grid that evolves noise into signal.
#[derive(Clone, Debug)]
pub struct EntropyGarden {
    pub width: u32,
    pub height: u32,
    pub cells: Vec<GardenCell>,
    pub shell: u8,
    pub windows_completed: u32,
    pub breath_count: u32,
}

#[derive(Clone, Debug, Default)]
pub struct DetonationResult {
    pub triggered: bool,
    pub energy: u32,
    pub corrections: u32,
    pub ceiling: u32,
    pub fragment_count: u32,
    pub heat: u32,
    pub blast_radius: u32,
    pub affected_cells: u32,
}

#[derive(Clone, Debug)]
pub struct GardenTickResult {
    pub window_completed: bool,
    pub shell: u8,
    pub standing_count: u32,
    pub resolved_count: u32,
    pub pink_count: u32,
    pub brown_count: u32,
    pub void_count: u32,
    pub coverage: f32,
}

impl EntropyGarden {
    pub fn new(width: u32, height: u32) -> Self {
        let mut cells = Vec::with_capacity((width * height) as usize);
        for y in 0..height {
            for x in 0..width {
                let seed = pseudo_random(x, y, 42);
                cells.push(GardenCell::new(x, y, seed));
            }
        }
        Self {
            width,
            height,
            cells,
            shell: 0,
            windows_completed: 0,
            breath_count: 0,
        }
    }

    /// Advance one breath (one phase of a triton window).
    /// Returns Some(result) when a triton window completes.
    pub fn breathe(&mut self) -> Option<GardenTickResult> {
        let phase = (self.breath_count as usize) % CLOCK_PERIOD;
        self.breath_count += 1;

        // Add new observation at this phase
        let structure_weight = 0.3 + self.shell as f32 * 0.15;
        let noise_weight = 1.0 - structure_weight;

        for cell in &mut self.cells {
            if cell.state == CellState::Resolved || cell.state == CellState::StandingWave {
                continue;
            }
            let noise = pseudo_random(cell.x, cell.y, self.breath_count);
            cell.observations[phase] = cell.seed * structure_weight + noise * noise_weight;
        }

        // Complete triton window every CLOCK_PERIOD breaths
        if phase != CLOCK_PERIOD - 1 {
            return None;
        }

        self.windows_completed += 1;
        let threshold = 0.001 * 10.0_f32.powi(self.shell as i32);

        let mut standing = 0u32;
        let mut resolved = 0u32;
        let mut pink = 0u32;
        let mut brown = 0u32;
        let mut void_count = 0u32;

        for cell in &mut self.cells {
            if cell.state == CellState::Resolved || cell.state == CellState::StandingWave {
                match cell.state {
                    CellState::StandingWave => standing += 1,
                    CellState::Resolved => resolved += 1,
                    _ => {}
                }
                continue;
            }

            let [a, b, c] = cell.observations;
            let mean = (a + b + c) / 3.0;
            cell.variance = ((a - mean).powi(2) + (b - mean).powi(2) + (c - mean).powi(2)) / 3.0;

            if cell.variance < 0.0001 {
                cell.state = CellState::StandingWave;
                cell.resolved_at = self.windows_completed as i32;
                standing += 1;
            } else if cell.variance < threshold {
                cell.state = CellState::Resolved;
                cell.resolved_at = self.windows_completed as i32;
                resolved += 1;
            } else if cell.variance < threshold * 10.0 {
                cell.state = CellState::Pink;
                pink += 1;
            } else if cell.variance < threshold * 100.0 {
                cell.state = CellState::Brown;
                brown += 1;
            } else {
                cell.state = CellState::Void;
                void_count += 1;
            }
        }

        // Shell promotion
        let windows_for_next = CLOCK_PERIOD.pow(self.shell as u32 + 1) as u32;
        if self.windows_completed >= windows_for_next && self.shell < 3 {
            self.shell += 1;
        }

        let total = self.cells.len() as f32;
        Some(GardenTickResult {
            window_completed: true,
            shell: self.shell,
            standing_count: standing,
            resolved_count: resolved,
            pink_count: pink,
            brown_count: brown,
            void_count,
            coverage: (standing + resolved) as f32 / total,
        })
    }

    /// Verify the central theorem at runtime: every resolved cell stays resolved.
    pub fn verify_irreversibility(&self) -> bool {
        for cell in &self.cells {
            if cell.resolved_at >= 0 {
                match cell.state {
                    CellState::Resolved | CellState::StandingWave => {}
                    _ => return false,
                }
            }
        }
        true
    }

    /// Detonate a nuclear explosion at (cx, cy), scattering fragment energy
    /// into surrounding cells. Uses DigitalHadronCollider collision physics.
    /// Fragments carry kinetic energy that becomes observation noise — the
    /// entropy from nuclear decay. Each detonation releases Landauer heat.
    ///
    /// Lean: DigitalHadronCollider.lean — collision_conserves_score
    /// Lean: VacuumOverflow.lean — cup_runneth_over_theorem
    /// Lean: LandauerPrincipleAsClinaemenDebt.lean — landauer_bound_per_bit
    pub fn detonate(&mut self, cx: u32, cy: u32, energy: u32) -> DetonationResult {
        let w = self.width;
        let h = self.height;
        if cx >= w || cy >= h {
            return DetonationResult::default();
        }

        // Collision: energy vs ceiling (Triton=3, Hexon=7, Decagon=10)
        let (triggered, corrections, ceiling) = if energy > 10 {
            (true, energy - 10, 10u32)
        } else if energy > 7 {
            (true, energy - 7, 7u32)
        } else if energy > 3 {
            (true, energy - 3, 3u32)
        } else {
            (false, 0u32, 0u32)
        };

        if !triggered {
            return DetonationResult {
                triggered: false,
                ..Default::default()
            };
        }

        let fragment_count = corrections.max(2);
        let heat = corrections; // Landauer: 1 Bule per erased bit
        let blast_radius = if energy > 0 {
            32 - energy.leading_zeros()
        } else {
            1
        };

        // Golden-angle fragment scatter into surrounding cells
        let golden_angle: f64 = 2.399_963_229_728_653;
        let speed = (corrections as f64).sqrt();
        let mut affected = 0u32;

        for i in 0..fragment_count {
            let y_norm = 1.0 - (2.0 * (i as f64 + 0.5)) / fragment_count.max(1) as f64;
            let ring = (1.0 - y_norm * y_norm).max(0.0).sqrt();
            let theta = i as f64 * golden_angle;

            let fx = cx as f64 + theta.cos() * ring * blast_radius as f64;
            let fy = cy as f64 + y_norm * blast_radius as f64;

            let tx = (fx.round() as i32).clamp(0, w as i32 - 1) as u32;
            let ty = (fy.round() as i32).clamp(0, h as i32 - 1) as u32;
            let idx = (ty * w + tx) as usize;

            if idx < self.cells.len() {
                let cell = &mut self.cells[idx];
                // Fragment energy becomes observation noise — the entropy injection
                let fragment_energy = speed * 0.1 / (i as f64 + 1.0);
                let phase = (self.breath_count as usize) % CLOCK_PERIOD;
                cell.observations[phase] += fragment_energy as f32;
                // Reset resolved state — fission can un-resolve (new observation noise)
                if cell.state == CellState::Resolved || cell.state == CellState::StandingWave {
                    cell.state = CellState::Void;
                    cell.resolved_at = -1;
                }
                affected += 1;
            }
        }

        DetonationResult {
            triggered: true,
            energy,
            corrections,
            ceiling,
            fragment_count,
            heat,
            blast_radius,
            affected_cells: affected,
        }
    }

    /// Detonate a bomb at a random cell using the breath count as position seed.
    /// Call once per breath for continuous entropy from nuclear decay.
    pub fn detonate_tick(&mut self) -> Option<DetonationResult> {
        let cx = pseudo_random(self.breath_count, 0, 7777) * self.width as f32;
        let cy = pseudo_random(0, self.breath_count, 8888) * self.height as f32;
        // Energy scales with cell count — bigger gardens = bigger bombs
        let energy = 4 + (self.width * self.height / 64).min(20);
        let result = self.detonate(cx as u32, cy as u32, energy);
        if result.triggered {
            Some(result)
        } else {
            None
        }
    }

    /// Breathe + detonate in correct order: increment breath, detonate (scatter
    /// fragments into observations), THEN classify on window completion.
    /// This is the "boost mode" — continuous fission prevents convergence.
    pub fn breathe_boost(
        &mut self,
        jitter_ns: u64,
        slot: u32,
        total_slots: u32,
    ) -> (Option<GardenTickResult>, Option<DetonationResult>) {
        let phase = (self.breath_count as usize) % CLOCK_PERIOD;
        self.breath_count += 1;

        // Step 1: Detonate (stoplight-gated) — BEFORE observations
        let det = if total_slots > 0 && (self.breath_count % total_slots) == slot {
            self.detonate_tick()
        } else {
            // Background radiation: small detonation every breath
            let cx = pseudo_random(self.breath_count, slot, 7777) * self.width as f32;
            let cy = pseudo_random(slot, self.breath_count, 8888) * self.height as f32;
            Some(self.detonate(cx as u32, cy as u32, 4)) // small bomb
        };

        // Step 2: Add observation with jitter mixed in
        let structure_weight = 0.3 + self.shell as f32 * 0.15;
        let noise_weight = 1.0 - structure_weight;
        let jitter_norm = (jitter_ns % 1_000_000) as f32 / 1_000_000.0;

        for cell in &mut self.cells {
            if cell.state == CellState::Resolved || cell.state == CellState::StandingWave {
                continue;
            }
            let base_noise = pseudo_random(cell.x, cell.y, self.breath_count);
            let mixed = base_noise * 0.7 + jitter_norm * 0.3;
            cell.observations[phase] = cell.seed * structure_weight + mixed * noise_weight;
        }

        // Step 3: Classify on window completion
        if phase != CLOCK_PERIOD - 1 {
            return (None, det);
        }

        self.windows_completed += 1;
        let threshold = 0.001 * 10.0_f32.powi(self.shell as i32);

        let mut standing = 0u32;
        let mut resolved = 0u32;
        let mut pink = 0u32;
        let mut brown = 0u32;
        let mut void_count = 0u32;

        for cell in &mut self.cells {
            if cell.state == CellState::Resolved || cell.state == CellState::StandingWave {
                match cell.state {
                    CellState::StandingWave => standing += 1,
                    CellState::Resolved => resolved += 1,
                    _ => {}
                }
                continue;
            }

            let [a, b, c] = cell.observations;
            let mean = (a + b + c) / 3.0;
            cell.variance = ((a - mean).powi(2) + (b - mean).powi(2) + (c - mean).powi(2)) / 3.0;

            if cell.variance < 0.0001 {
                cell.state = CellState::StandingWave;
                cell.resolved_at = self.windows_completed as i32;
                standing += 1;
            } else if cell.variance < threshold {
                cell.state = CellState::Resolved;
                cell.resolved_at = self.windows_completed as i32;
                resolved += 1;
            } else if cell.variance < threshold * 10.0 {
                cell.state = CellState::Pink;
                pink += 1;
            } else if cell.variance < threshold * 100.0 {
                cell.state = CellState::Brown;
                brown += 1;
            } else {
                cell.state = CellState::Void;
                void_count += 1;
            }
        }

        let windows_for_next = CLOCK_PERIOD.pow(self.shell as u32 + 1) as u32;
        if self.windows_completed >= windows_for_next && self.shell < 3 {
            self.shell += 1;
        }

        let total = self.cells.len() as f32;
        (
            Some(GardenTickResult {
                window_completed: true,
                shell: self.shell,
                standing_count: standing,
                resolved_count: resolved,
                pink_count: pink,
                brown_count: brown,
                void_count,
                coverage: (standing + resolved) as f32 / total,
            }),
            det,
        )
    }

    /// Stoplight-scheduled detonation: only fires during this agent's green window.
    /// Slot assignment: agent_id % slot_count. Green window = 1 breath per cycle.
    /// This prevents entropy pile-on — detonations are "just in time."
    ///
    /// Lean: QuasicrystalStoplightTiming.lean — per-subscriber green windows
    pub fn detonate_stoplight(&mut self, slot: u32, total_slots: u32) -> Option<DetonationResult> {
        if total_slots == 0 {
            return None;
        }
        let current_slot = self.breath_count % total_slots;
        if current_slot != slot {
            return None;
        }
        self.detonate_tick()
    }

    /// Count cells by state.
    pub fn census(&self) -> GardenTickResult {
        let mut s = 0u32;
        let mut r = 0u32;
        let mut p = 0u32;
        let mut b = 0u32;
        let mut v = 0u32;
        for cell in &self.cells {
            match cell.state {
                CellState::StandingWave => s += 1,
                CellState::Resolved => r += 1,
                CellState::Pink => p += 1,
                CellState::Brown => b += 1,
                CellState::Void => v += 1,
            }
        }
        let total = self.cells.len() as f32;
        GardenTickResult {
            window_completed: false,
            shell: self.shell,
            standing_count: s,
            resolved_count: r,
            pink_count: p,
            brown_count: b,
            void_count: v,
            coverage: (s + r) as f32 / total,
        }
    }
}

// ─── Deterministic pseudo-random (no external deps) ─────────────────────────

fn pseudo_random(x: u32, y: u32, salt: u32) -> f32 {
    let mut h = x
        .wrapping_mul(374761393)
        .wrapping_add(y.wrapping_mul(668265263))
        .wrapping_add(salt.wrapping_mul(1274126177));
    h = (h ^ (h >> 13)).wrapping_mul(1103515245);
    h = h ^ (h >> 16);
    (h & 0x7fffff) as f32 / 0x7fffff as f32
}

impl EntropyGarden {
    /// Seeded garden: each agent gets a unique universe via agent_seed.
    pub fn new_seeded(width: u32, height: u32, agent_seed: u64) -> EntropyGarden {
        let mut cells = Vec::with_capacity((width * height) as usize);
        for y in 0..height {
            for x in 0..width {
                let seed = pseudo_random(
                    x.wrapping_add(agent_seed as u32),
                    y.wrapping_add((agent_seed >> 32) as u32),
                    42,
                );
                cells.push(GardenCell::new(x, y, seed));
            }
        }
        EntropyGarden {
            width,
            height,
            cells,
            shell: 0,
            windows_completed: 0,
            breath_count: 0,
        }
    }
}

impl EntropyGarden {
    /// Alias: breathe with jitter (delegates to breathe_boost with no stoplight).
    pub fn breathe_with_jitter(&mut self, jitter_ns: u64) -> Option<GardenTickResult> {
        let (result, _) = self.breathe_boost(jitter_ns, 0, 1); // slot 0 of 1 = always fires
        result
    }
}

// ─── DFT-based cache key prediction ────────────────────────────────────────
//
// Standing waves are RECURRING patterns. Their dominant frequency tells us
// WHAT recurs. Cells that oscillate at the same frequency are the same
// pattern. By grouping standing/resolved cells by frequency bin and hashing
// the (bin, shell, garden_seed) triple via FNV-1a, we predict the next
// likely query shape key. This replaces random-entropy key generation with
// targeted speculation.
//
// Lean: EntropyBoostCrossover.predicted_hit_rate_geq_random

/// Frequency bin width for grouping cells with similar dominant frequency.
const FREQUENCY_BIN_WIDTH: f32 = 0.05;

/// Maximum number of predicted keys (one per Phyle direction).
const MAX_PREDICTED_KEYS: usize = 27;

/// FNV-1a hash of a byte slice, returning u64.
fn fnv1a_hash(bytes: &[u8]) -> u64 {
    let mut h: u64 = 0xcbf29ce484222325;
    for &b in bytes {
        h ^= b as u64;
        h = h.wrapping_mul(0x100000001b3);
    }
    h
}

/// Compute dominant frequency of a cell's observation buffer via single-bin DFT.
/// For a 3-sample window (triton), the dominant frequency is the magnitude of
/// the first DFT bin (the only non-DC bin for N=3).
fn dominant_frequency(observations: &[f32; 3]) -> f32 {
    // DFT bin k=1 for N=3: X[1] = sum_{n=0}^{2} x[n] * e^{-i*2*pi*n/3}
    // Real part: x[0] + x[1]*cos(2pi/3) + x[2]*cos(4pi/3)
    //          = x[0] - 0.5*x[1] - 0.5*x[2]
    // Imag part: -x[1]*sin(2pi/3) - x[2]*sin(4pi/3)
    //          = -x[1]*0.866 + x[2]*0.866
    let [a, b, c] = *observations;
    let real = a - 0.5 * b - 0.5 * c;
    let imag = 0.866_025_4 * (c - b);
    (real * real + imag * imag).sqrt()
}

/// Spectral entropy of a cell's observation buffer.
/// Lower values = more predictable (energy concentrated in fewer bins).
fn spectral_entropy(observations: &[f32; 3]) -> f32 {
    let [a, b, c] = *observations;
    let dc = (a + b + c) / 3.0;
    let dc_power = dc * dc;
    let freq_mag = dominant_frequency(observations);
    let freq_power = freq_mag * freq_mag;
    let total = dc_power + freq_power;
    if total < 1e-12 {
        return 1.0; // uniform = max entropy
    }
    // Normalized Shannon entropy over 2 bins
    let p_dc = dc_power / total;
    let p_freq = freq_power / total;
    let mut h = 0.0f32;
    if p_dc > 1e-12 {
        h -= p_dc * p_dc.ln();
    }
    if p_freq > 1e-12 {
        h -= p_freq * p_freq.ln();
    }
    h / core::f32::consts::LN_2 // normalize to [0, 1]
}

impl EntropyGarden {
    /// Predict the next likely cache shape keys by analyzing DFT dominant
    /// frequencies from standing wave and resolved cells.
    ///
    /// Standing waves are recurring patterns. Cells oscillating at the same
    /// frequency represent the same pattern. We group by frequency bin, then
    /// generate a predicted key per group using FNV-1a(bin, shell, garden_seed).
    ///
    /// Returns up to 27 predicted keys (one per Phyle direction).
    ///
    /// Lean: EntropyBoostCrossover.predicted_hit_rate_geq_random
    pub fn predict_next_keys(&self) -> Vec<u64> {
        // Step 1: collect dominant frequencies from standing/resolved cells
        let mut freq_cells: Vec<(f32, f32, u32, u32)> = Vec::new(); // (freq, spectral_entropy, x, y)
        for cell in &self.cells {
            match cell.state {
                CellState::StandingWave | CellState::Resolved => {
                    let freq = dominant_frequency(&cell.observations);
                    let se = spectral_entropy(&cell.observations);
                    freq_cells.push((freq, se, cell.x, cell.y));
                }
                _ => {}
            }
        }

        if freq_cells.is_empty() {
            return Vec::new();
        }

        // Step 2: group by frequency bin
        // Sort by frequency for stable binning
        freq_cells.sort_by(|a, b| a.0.partial_cmp(&b.0).unwrap_or(core::cmp::Ordering::Equal));

        let mut bins: Vec<(f32, u32)> = Vec::new(); // (sum_of_freqs, count)
        let mut current_bin_start = freq_cells[0].0;
        let mut current_sum = 0.0f32;
        let mut current_count = 0u32;

        for &(freq, _se, _x, _y) in &freq_cells {
            if freq - current_bin_start > FREQUENCY_BIN_WIDTH && current_count > 0 {
                bins.push((current_sum, current_count));
                current_bin_start = freq;
                current_sum = 0.0;
                current_count = 0;
            }
            current_sum += freq;
            current_count += 1;
        }
        if current_count > 0 {
            bins.push((current_sum, current_count));
        }

        // Step 3: sort bins by population (most populated = strongest pattern)
        bins.sort_by(|a, b| b.1.cmp(&a.1));

        // Step 4: generate predicted keys from top bins
        // Garden seed: derive from dimensions + shell + breath_count + cell seeds
        // The cell seed fingerprint ensures different seeded gardens produce
        // different predictions even with identical structure.
        let cell_fingerprint = self.cells.iter().fold(0u64, |acc, c| {
            acc.wrapping_mul(0x100000001b3)
                .wrapping_add(c.seed.to_bits() as u64)
        });
        let garden_seed = (self.width as u64)
            .wrapping_mul(0x9e3779b97f4a7c15)
            .wrapping_add(self.height as u64)
            .wrapping_add(self.breath_count as u64)
            .wrapping_add(cell_fingerprint);

        let mut keys = Vec::with_capacity(bins.len().min(MAX_PREDICTED_KEYS));
        for (sum, count) in bins.iter().take(MAX_PREDICTED_KEYS) {
            let avg_freq = sum / (*count as f32);
            // Quantize to bin index for deterministic keying
            let bin_index = (avg_freq / FREQUENCY_BIN_WIDTH) as u32;

            // FNV-1a hash of (frequency_bin, shell, garden_seed)
            let mut hash_input = Vec::with_capacity(14);
            hash_input.extend_from_slice(&bin_index.to_le_bytes());
            hash_input.extend_from_slice(&[self.shell]);
            hash_input.extend_from_slice(&garden_seed.to_le_bytes());
            // Mix in bin population as a confidence weight
            hash_input.extend_from_slice(&count.to_le_bytes());

            keys.push(fnv1a_hash(&hash_input));
        }

        keys
    }
}

